#include <iostream>
#include <iomanip>
#include <vector>
#include <cmath>

using namespace std;

// Function to generate a sequence of numbers
vector<int> generateSequence(int n) {
    vector<int> sequence;
    for (int i = 1; i <= n; ++i) {
        sequence.push_back(i * 2);
    }
    return sequence;
}

// Function to print a pattern based on a sequence
void printPattern(vector<int> sequence) {
    int size = sequence.size();
    for (int i = 0; i < size; ++i) {
        for (int j = 0; j < size; ++j) {
            if (i == j) {
                cout << sequence[j] << " ";
            } else if (i + j == size - 1) {
                cout << sequence[j] << " ";
            } else {
                cout << "  ";
            }
        }
        cout << endl;
    }
}

int main() {
    int n = 5;
    vector<int> seq = generateSequence(n);
    printPattern(seq);
    return 0;
}
